import * as React from "react"

import { cn } from "@/lib/utils"

function Card({ className, ...props }: React.ComponentProps<"div">) {
  return <div data-slot="card" className={cn("bp-card text-[var(--semantic-text-strong)]", className)} {...props} />
}

function CardHeader({ className, ...props }: React.ComponentProps<"div">) {
  return <div data-slot="card-header" className={cn("flex flex-col gap-1.5 p-6", className)} {...props} />
}

function CardTitle({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="card-title"
      className={cn("font-semibold leading-none tracking-tight text-[var(--semantic-text-strong)]", className)}
      {...props}
    />
  )
}

function CardDescription({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="card-description"
      className={cn("text-sm text-[var(--semantic-text-body)]", className)}
      {...props}
    />
  )
}

function CardContent({ className, ...props }: React.ComponentProps<"div">) {
  return <div data-slot="card-content" className={cn("p-6 pt-0", className)} {...props} />
}

function CardFooter({ className, ...props }: React.ComponentProps<"div">) {
  return <div data-slot="card-footer" className={cn("flex items-center p-6 pt-0", className)} {...props} />
}

export { Card, CardHeader, CardFooter, CardTitle, CardDescription, CardContent }

import * as React from "react"

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { cn } from "@/lib/utils"

type BlueprintCardProps = {
  title?: React.ReactNode
  description?: React.ReactNode
  interactive?: boolean
  className?: string
  headerClassName?: string
  contentClassName?: string
  children?: React.ReactNode
}

function BlueprintCard({
  title,
  description,
  interactive = false,
  className,
  headerClassName,
  contentClassName,
  children
}: BlueprintCardProps) {
  return (
    <Card className={cn(interactive && "bp-card-interactive", className)}>
      {(title || description) && (
        <CardHeader className={headerClassName}>
          {title ? <CardTitle>{title}</CardTitle> : null}
          {description ? <CardDescription>{description}</CardDescription> : null}
        </CardHeader>
      )}

      <CardContent className={cn(!title && !description && "p-6", contentClassName)}>{children}</CardContent>
    </Card>
  )
}

export { BlueprintCard }
